/**
 * Universal BLOCK_* parameterNames (BLOCK_PAN, BLOCK_MIX, BLOCK_LEVEL,
 * BLOCK_BYPASS, BLOCK_BYPASSMODE, etc.) — apply to every block.
 * Each block exposes these at the same cache_id.
 */
export const UNIVERSAL_BLOCK_PARAMETERS: Readonly<Record<string, number>> = {
};

/**
 * Resolve a (block, parameterName) pair to a cache_id, preferring the
 * unambiguous case. Returns:
 *   - undefined if not found
 *   - the single cache_id if exactly one variant binds it
 *   - the first cache_id if multiple variants disagree (caller may want
 *     to call resolveAllCacheIds for the full ambiguity set).
 */
export function resolveCacheId(block: string, parameterName: string): number | undefined {
    if (UNIVERSAL_BLOCK_PARAMETERS[parameterName] !== undefined) {
        return UNIVERSAL_BLOCK_PARAMETERS[parameterName];
    }
    const cids = PARAMETER_NAME_TO_CACHE_ID[block]?.[parameterName];
    return cids && cids.length > 0 ? cids[0] : undefined;
}

/** Same as resolveCacheId but returns every variant's cache_id (may be > 1). */
export function resolveAllCacheIds(block: string, parameterName: string): readonly number[] {
    if (UNIVERSAL_BLOCK_PARAMETERS[parameterName] !== undefined) {
        return [UNIVERSAL_BLOCK_PARAMETERS[parameterName]];
    }
    return PARAMETER_NAME_TO_CACHE_ID[block]?.[parameterName] ?? [];
}
